const contentBlocks = $json.message?.content;

const textFromBlocks = Array.isArray(contentBlocks)
  ? contentBlocks
      .filter((block) => block?.type === "text" && typeof block.text === "string")
      .map((block) => block.text.trim())
      .filter(Boolean)
      .join("\n")
  : typeof contentBlocks === "string"
    ? contentBlocks
    : "";

const rawCandidates = [
  typeof $json.text === "string" ? $json.text : "",
  textFromBlocks,
  typeof $json.output === "string" ? $json.output : "",
  typeof $json.response?.generations?.[0]?.text === "string"
    ? $json.response.generations[0].text
    : "",
];

const raw = rawCandidates.find((value) => value.trim()) || "";

if (!raw) {
  return {
    success: false,
    category: "Parse Error",
    severity: "Low",
    action: "AI returned unreadable format. Check n8n execution logs.",
    shouldNotifySlack: false
  };
}

const fencedMatch = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
const jsonText = fencedMatch?.[1]?.trim() || raw.match(/\{[\s\S]*\}/)?.[0] || "";

if (!jsonText) {
  return {
    success: false,
    category: "Parse Error",
    severity: "Low",
    action: "AI returned unreadable format. Check n8n execution logs.",
    shouldNotifySlack: false
  };
}

let parsed;
try {
  parsed = JSON.parse(jsonText);
} catch {
  return {
    success: false,
    category: "Parse Error",
    severity: "Low",
    action: "AI returned malformed JSON.",
    shouldNotifySlack: false
  };
}

const severityRaw = String(parsed.severity || "")
  .trim()
  .toLowerCase()
  .replace(/[^\w]/g, "");

const severityMap = {
  low: "Low",
  medium: "Medium",
  high: "High"
};

const severity = severityMap[severityRaw] || "Low";
const category = String(parsed.category || "General").trim() || "General";
const action =
  String(parsed.action || "No specific action recommended").trim() ||
  "No specific action recommended";

return {
  success: true,
  category,
  severity,
  action,
  shouldNotifySlack: severity === "High"
};
